func (a *adapter) DeleteCustomer(ctx context.Context, input customer.DeleteCustomerInput) error {
	if err := input.Validate(); err != nil {
		return models.NewGenericValidationError(fmt.Errorf("error deleting customer: %w", err))
	}
	return entutils.TransactingRepoWithNoValue(ctx, a, func(ctx context.Context, repo *adapter) error {
		deletedAt := clock.Now().UTC()
		rows, err := repo.db.Customer.Update().
			Where(customerdb.ID(input.ID), customerdb.Namespace(input.Namespace), customerdb.DeletedAtIsNil()).
			SetDeletedAt(deletedAt).Save(ctx)
		if err != nil { return fmt.Errorf("failed to delete customer: %w", err) }
		if rows == 0 { return models.NewGenericNotFoundError(fmt.Errorf("customer with id %s not found in %s namespace", input.ID, input.Namespace)) }
		return nil
	})
}

func AsCustomerApp(customerAppCandidate app.App) (App, error) {
	customerApp, ok := customerAppCandidate.(App)
	if !ok {
		return nil, models.NewGenericValidationError(
			fmt.Errorf("is not a customer app [id=%s, type=%s]", customerAppCandidate.GetID(), customerAppCandidate.GetType()),
		)
	}
	return customerApp, nil
}

func (h *handler) CreateCustomer() CreateCustomerHandler {
	return httptransport.NewHandler(
		func(ctx context.Context, r *http.Request) (CreateCustomerRequest, error) {
			body := api.CustomerCreate{}
			if err := commonhttp.JSONRequestBodyDecoder(r, &body); err != nil {
				return CreateCustomerRequest{}, fmt.Errorf("field to decode create customer request: %w", err)
			}
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return CreateCustomerRequest{}, err }
			return CreateCustomerRequest{Namespace: ns, CustomerMutate: MapCustomerCreate(body)}, nil
		},
		func(ctx context.Context, request CreateCustomerRequest) (CreateCustomerResponse, error) {
			customer, err := h.service.CreateCustomer(ctx, request)
			if err != nil { return CreateCustomerResponse{}, err }
			return h.mapCustomerWithSubscriptionsToAPI(ctx, *customer, nil)
		},
		commonhttp.JSONResponseEncoderWithStatus[CreateCustomerResponse](http.StatusCreated),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("createCustomer"))...,
	)
}
